    if (cmd == "shamir-rotate")   return cmd_shamir_rotate   (argc - 2, argv + 2);
    if (cmd == "envelope")        return cmd_envelope       (argc - 2, argv + 2);
    if (cmd == "inspect-envelope") return cmd_inspect_envelope(argc - 2, argv + 2);
